+    fn sqlite_master_column_index(column: &str) -> Result<usize> {
+        match column.to_ascii_lowercase().as_str() {
+            "type" => Ok(0),
+            "name" => Ok(1),
+            "tbl_name" => Ok(2),
+            "rootpage" => Ok(3),
+            "sql" => Ok(4),
+            "rowid" | "_rowid_" | "oid" => Err(FrankenError::NotImplemented(
+                "writable_schema rowid writes are not supported".to_owned(),
+            )),
+            other => Err(FrankenError::Internal(format!(
+                "column '{other}' not found in sqlite_master"
+            ))),
+        }
+    }
+
+    fn sqlite_master_eval_col_map(table_name: &str) -> [(String, String, bool); 5] {
+        [
+            (table_name.to_owned(), "type".to_owned(), false),
+            (table_name.to_owned(), "name".to_owned(), false),
+            (table_name.to_owned(), "tbl_name".to_owned(), false),
+            (table_name.to_owned(), "rootpage".to_owned(), false),
+            (table_name.to_owned(), "sql".to_owned(), false),
