+    fn sqlite_master_insert_row_from_values(
+        columns: &[String],
+        values: &[SqliteValue],
+    ) -> Result<Vec<SqliteValue>> {
+        if columns.is_empty() {
+            if values.len() != 5 {
+                return Err(FrankenError::Internal(format!(
+                    "sqlite_master INSERT expected 5 values, got {}",
+                    values.len()
+                )));
+            }
+            return Ok(values.to_vec());
+        }
+        if columns.len() != values.len() {
+            return Err(FrankenError::Internal(format!(
+                "sqlite_master INSERT has {} target columns but {} values",
+                columns.len(),
+                values.len()
+            )));
+        }
+
+        let mut row = vec![SqliteValue::Null; 5];
+        for (column, value) in columns.iter().zip(values) {
+            let idx = Self::sqlite_master_column_index(column)?;
+            row[idx] = value.clone();
+        }
+        Ok(row)
+    }
